twitter.map:
function (doc) {
  if (doc.we_source && doc.we_source === "twitter" && doc.id_str && doc.we_timestamp) {
    emit(doc.we_timestamp, doc.id_str);
  }
}

identica.map:
function (doc) {
  if (doc.we_source && doc.we_source === "identica" && doc.we_timestamp && doc.id) {
    if (doc.we_tags) {
      for (var i=0; i<doc.we_tags.length; i++) {
        emit([doc.we_tags[i], doc.we_timestamp], doc.id);
      }
    } else if (doc.we_tag) {
      emit([doc.we_tag, doc.we_timestamp], doc.id);
    }
  }
}

