google.map:
function (doc) {
  if (doc.we_source && doc.we_source === "g+" && doc.id && doc.object && doc.object.replies && doc.object.plusoners && doc.object.resharers) {
    emit(doc.id, [doc._rev, doc.we_tags,
doc.object.replies.totalItems, doc.object.plusoners.totalItems, doc.object.resharers.totalItems]);
  }
}

